body {
    font-family: "Inter", sans-serif; /* Replace with your actual web font */
    font-synthesis: none; /* Crucial for preventing artificial bold/italic rendering */
}

/* Example: Apply it to specific headings for maximum impact */
h1, h2, h3 {
    font-weight: 700; /* Ensure you're loading a genuine bold variant */
    font-synthesis: none;
}

p {
    font-style: italic; /* Ensure you're loading a genuine italic variant */
    font-synthesis: none;
}
